import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
import { prisma } from "@/lib/db";

const createNotificationSchema = z.object({
  userId: z.string().uuid("Некоректний ID користувача"),
  text: z.string().min(1).max(1000).optional(),
  type: z.enum(["INFO", "BID", "OUTBID", "WON", "SOLD", "SHIPMENT"]).optional().default("INFO"),
  markAllAsRead: z.boolean().optional(),
});

export async function GET(req: NextRequest) {
  const userId = new URL(req.url).searchParams.get("userId");
  if (!userId) return NextResponse.json({ error: "Не вказано userId" }, { status: 400 });

  try {
    const notifications = await prisma.notification.findMany({
      where: { userId },
      orderBy: { createdAt: "desc" },
    });
    return NextResponse.json({ notifications });
  } catch {
    return NextResponse.json({ error: "Внутрішня помилка сервера" }, { status: 500 });
  }
}

export async function POST(req: NextRequest) {
  try {
    const body = await req.json();
    const parsed = createNotificationSchema.parse(body);

    if (parsed.markAllAsRead) {
      await prisma.notification.updateMany({
        where: { userId: parsed.userId, isRead: false },
        data: { isRead: true },
      });
      return NextResponse.json({ success: true });
    }

    if (!parsed.text) {
      return NextResponse.json({ error: "Текст сповіщення обов'язковий" }, { status: 400 });
    }

    const notif = await prisma.notification.create({
      data: { userId: parsed.userId, text: parsed.text, type: parsed.type, isRead: false },
    });
    return NextResponse.json({ success: true, notification: notif });
  } catch (error) {
    if (error instanceof z.ZodError) {
      return NextResponse.json({ error: error.errors[0].message }, { status: 400 });
    }
    return NextResponse.json({ error: "Внутрішня помилка сервера" }, { status: 500 });
  }
}
